// ===== RECRUITER LEAD CONFIG (AGING LISTINGS, CUSTOM FORM) =====
// Premise: surface job postings that have been open a long time as recruiter
// leads. A long-open role is a company that needs help filling it. Driven by
// the webhook POST body; emits one { json: config } for the scraper chain.

const trigger = $input.first().json || {};
const body = (trigger.body && typeof trigger.body === 'object') ? trigger.body : trigger;
function fail(msg) { throw new Error('Recruiter lead config error: ' + msg); }

// niche the recruiter places for -> scrape queries + title-match anchors
let keywordList = [];
if (Array.isArray(body.niche_keywords)) keywordList = body.niche_keywords.map(k => String(k||'').trim()).filter(Boolean);
else if (typeof body.niche_keywords === 'string') keywordList = body.niche_keywords.split(',').map(s=>s.trim()).filter(Boolean);
if (keywordList.length === 0 && typeof body.keywords === 'string') keywordList = body.keywords.split(',').map(s=>s.trim()).filter(Boolean);
if (keywordList.length === 0) fail('niche_keywords is required (comma-separated string or array)');
if (keywordList.length > 20) fail('niche_keywords too long (max 20)');

const location = String(body.location || '').trim();
if (!location) fail('location is required');

const workplaceRaw = String(body.workplace_type || 'any').toLowerCase().trim();
let workTypes;
if (workplaceRaw === 'remote') workTypes = ['remote'];
else if (workplaceRaw === 'hybrid') workTypes = ['hybrid'];
else if (workplaceRaw === 'on-site' || workplaceRaw === 'onsite') workTypes = ['onsite'];
else workTypes = ['remote', 'hybrid'];

// staleness floor: only postings at least this old count as leads
const minAgeWeeks = Math.max(1, Math.min(26, Number(body.min_posting_age_weeks) || 4));
const minPostingAgeDays = minAgeWeeks * 7;
const excludeStaffing = body.exclude_staffing_firms === undefined ? true : !!body.exclude_staffing_firms;

const pages = Math.max(1, Math.min(5, Number(body.pages) || 3));
const maxResultsPerSearch = pages * 25;
const campaignLabel = String(body.campaign_label || body.run_label || '').trim().slice(0, 80);

// Find AGING roles: use the widest window LinkedIn exposes, then rank by age.
// LinkedIn's date filter caps around past_month; observed persistence
// (times_seen in seen_leads across repeated scans) is the durable signal.
const datePosted = 'past_month';

const HARD_QUERY_CAP = 10;
if (keywordList.length * workTypes.length > HARD_QUERY_CAP) {
  const maxKw = Math.max(1, Math.floor(HARD_QUERY_CAP / workTypes.length));
  keywordList = keywordList.slice(0, maxKw);
}

const config = {
  workflowScope: 'recruiter_leads',
  _campaignLabel: campaignLabel,
  _minPostingAgeDays: minPostingAgeDays,
  _excludeStaffing: excludeStaffing,
  _customRequest: { niche_keywords: keywordList, location, workplace_type: workplaceRaw, min_posting_age_weeks: minAgeWeeks, pages, campaign_label: campaignLabel },
  indeedSearches: [],
  linkedinSearches: [],
  datePosted,
  maxResultsPerSearch,
  includeComparisonWindow: false,
  comparisonMaxResults: 0,
  fetchFullDescription: true,
  enrichWithAI: false,
  linkedinCookie: $env.LINKEDIN_COOKIE || '',
  actorProxyConfig: {},
  runGuardEnabled: false,
  runGuardMinMinutes: 0,
  maxQueriesPerRun: HARD_QUERY_CAP,
  safeMode: false, safeMaxQueries: 2, safeMaxResults: 10, safeFetchFullDescription: true,
  testMode: false, testMaxQueries: 2, testMaxResults: 10, testFetchFullDescription: false,
  scoring: {
    minPostingAgeDays,
    excludeStaffing,
    nicheKeywords: keywordList,
    seniorityWords: ['chief','vp','vice president','director','head of','senior director','principal','staff','lead','senior','sr.','sr '],
    hiringIntentKeywords: ['urgently hiring','urgent','immediate','immediately','multiple openings','several openings','actively hiring','fast-growing','fast growing','rapidly growing','backfill','reposted'],
    staffingFirmTerms: ['staffing','recruiting','recruitment','talent solutions','talent partners','search partners','executive search','consultants','consulting group','headhunt','staffing agency','rpo'],
    noAgencyTerms: ['no agencies','no recruiters','direct applicants only','direct hire only','principals only'],
    highLeadThreshold: 50
  },
  slackWebhookUrl: $env.SLACK_WEBHOOK_URL || ''
};

const searches = [];
for (const kw of keywordList) {
  for (const wt of workTypes) {
    searches.push({ keywords: kw, location, workType: wt, datePosted, maxResults: maxResultsPerSearch, scope: 'recruiter_leads', planId: 'lead_' + (campaignLabel||'unlabeled').replace(/[^a-z0-9_-]/gi,'_'), windowId: 'primary' });
  }
}
config.linkedinSearches = searches.slice(0, HARD_QUERY_CAP);
config._abortRun = false;
config._abortReason = '';
return [{ json: config }];

// Split LinkedIn searches into individual items
const config = $input.first().json;

if (config._abortRun) {
  console.log(config._abortReason || 'Run aborted by guard.');
  return [];
}

const scope = config.workflowScope || 'default';
const staticData = $getWorkflowStaticData('global');

// Guard 1: never emit twice within the same execution
const execGuardKey = `splitLastExecutionId_${scope}`;
const currentExecutionId = String($execution.id || '');
if (staticData[execGuardKey] === currentExecutionId) {
  return [];
}
staticData[execGuardKey] = currentExecutionId;

const searches = Array.isArray(config.linkedinSearches) ? config.linkedinSearches : [];

// Safety dedupe in case upstream config accidentally repeats query tuples
const seen = new Set();
const uniqueSearches = [];
for (const search of searches) {
  const key = [
    search.keywords,
    search.location,
    search.workType,
    search.datePosted,
    search.windowId || 'primary'
  ]
    .map(v => String(v || '').toLowerCase().trim())
    .join('|');

  if (seen.has(key)) continue;
  seen.add(key);
  uniqueSearches.push(search);
}

// Guard 2 (global fail-safe): max 10 actor calls per role per 15-minute window
const HARD_MAX_QUERIES = 10;
const BUDGET_WINDOW_MINUTES = 15;
const budgetKey = `splitBudget_${scope}`;
const now = Date.now();
let budget = staticData[budgetKey] || { windowStartMs: now, count: 0 };

const windowMs = BUDGET_WINDOW_MINUTES * 60 * 1000;
if (!budget.windowStartMs || (now - Number(budget.windowStartMs)) >= windowMs) {
  budget = { windowStartMs: now, count: 0 };
}

const configuredMax = Math.max(1, Number(config.maxQueriesPerRun ?? HARD_MAX_QUERIES));
const remainingBudget = Math.max(0, HARD_MAX_QUERIES - Number(budget.count || 0));
const effectiveMax = Math.min(HARD_MAX_QUERIES, configuredMax, remainingBudget);

if (effectiveMax <= 0) {
  return [];
}

const finalSearches = uniqueSearches.slice(0, effectiveMax);

budget.count = Number(budget.count || 0) + finalSearches.length;
staticData[budgetKey] = budget;

return finalSearches.map((search, idx) => ({
  json: {
    ...search,
    _queryIndex: idx + 1,
    _queryCount: finalSearches.length,
    fetchFullDescription: typeof search.fetchFullDescription === 'boolean'
      ? search.fetchFullDescription
      : !!config.fetchFullDescription,
    enrichWithAI: !!config.enrichWithAI,
    linkedinCookie: config.linkedinCookie || '',
    actorProxyConfig: config.actorProxyConfig || {},
    _config: config,
  }
}));

// Normalize Mfrostbutter/linkedin-jobs-scraper output to unified job schema
const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  // Our actor always emits title + companyName; skip empty records
  if (!d || !d.title) continue;

  const loc = d.location || '';
  const workplaceType = d.workRemoteAllowed
    ? (d.workplaceTypes && d.workplaceTypes[0]) || 'Remote'
    : 'On-site';

  // salary_low/salary_high come from parser; salary is the raw string
  let salaryMin = d.salary_low || null;
  let salaryMax = d.salary_high || null;

  // Carry config forward when available. Actor dataset items usually drop upstream fields,
  // so fallback to Config node when this workflow path includes it.
  let cfg = item.json._config;
  if (!cfg) {
    try {
      cfg = $('Config').first()?.json || null;
    } catch (e) {
      cfg = null;
    }
  }

  results.push({
    jobTitle: d.title || '',
    company: d.companyName || '',
    location: loc,
    source: 'LinkedIn',
    sourceId: d.id || `li-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    sourceUrl: d.link || d.applyUrl || '',
    postedDate: d.postedAt || new Date().toISOString(),
    salaryMin: salaryMin,
    salaryMax: salaryMax,
    employmentType: 'Full-time',
    workplaceType: workplaceType,
    companySize: '',
    companyIndustry: '',
    descriptionSnippet: (d.descriptionText || '').substring(0, 500),
    fullDescription: d.descriptionText || '',
    easyApply: false,
    applicants: null,
    _config: cfg,
  });
}

return results.map(r => ({ json: r }));

// ===== DEDUP + LEAD SCORE (AGING LISTINGS) =====
// Dedup within the batch, DROP postings younger than the staleness floor and
// staffing/recruiting firms, then score the rest as recruiter leads.
// Older + harder-to-fill + on-niche + hiring-intent = higher lead score.

const items = $input.all();

const DEFAULT = {
  minPostingAgeDays: 28, excludeStaffing: true, nicheKeywords: [],
  seniorityWords: ['chief','vp','vice president','director','head of','senior director','principal','staff','lead','senior'],
  hiringIntentKeywords: ['urgently hiring','urgent','immediate','multiple openings','actively hiring','fast-growing','reposted','backfill'],
  staffingFirmTerms: ['staffing','recruiting','recruitment','talent solutions','executive search','consultants','headhunt','rpo'],
  noAgencyTerms: ['no agencies','no recruiters','direct applicants only','principals only'],
  highLeadThreshold: 50
};
const cfg = (items[0]?.json?._config?.scoring && typeof items[0].json._config.scoring === 'object') ? items[0].json._config.scoring : DEFAULT;
const carryConfig = items[0]?.json?._config || null;

function ageDays(postedDate) {
  if (!postedDate) return null;
  const t = Date.parse(postedDate);
  if (!Number.isFinite(t)) return null;
  const d = Math.floor((Date.now() - t) / 86400000);
  return d >= 0 ? d : null;
}

// dedup within batch by title + company
const seen = new Set();
const unique = [];
for (const item of items) {
  const d = item.json;
  const key = `${(d.jobTitle||'').toLowerCase().trim()}|${(d.company||'').toLowerCase().trim()}`;
  if (seen.has(key)) continue;
  seen.add(key);
  unique.push(d);
}

function isStaffingFirm(company) {
  const c = (company||'').toLowerCase();
  return (cfg.staffingFirmTerms||[]).some(t => c.includes(t));
}

function scoreLead(job, age) {
  const breakdown = [];
  let score = 0;
  const titleLower = (job.jobTitle||'').toLowerCase();
  const descLower = (job.fullDescription||'').toLowerCase();

  // Staleness (primary). Older = better. ~5 pts/week, capped at 45.
  const weeks = age / 7;
  const stale = Math.min(45, Math.round(weeks * 5));
  score += stale;
  breakdown.push('Aging posting (' + age + 'd, ~' + weeks.toFixed(1) + 'w): +' + stale);

  const niche = (cfg.nicheKeywords||[]).map(k => String(k).toLowerCase());
  if (niche.some(k => k && titleLower.includes(k))) { score += 25; breakdown.push('Niche title match: +25'); }
  if ((cfg.seniorityWords||[]).some(w => titleLower.includes(w))) { score += 10; breakdown.push('Senior / hard-to-fill: +10'); }
  if ((cfg.hiringIntentKeywords||[]).some(k => descLower.includes(k))) { score += 10; breakdown.push('Hiring-intent signal: +10'); }

  const sizeMatch = (job.companySize||'').replace(/,/g,'').match(/(\d+)/);
  if (sizeMatch) { const s = parseInt(sizeMatch[1]); if (s>=50 && s<=2000) { score += 10; breakdown.push('Mid-market size: +10'); } }

  if ((cfg.noAgencyTerms||[]).some(k => descLower.includes(k))) { score -= 30; breakdown.push('Says no agencies: -30'); }

  return { leadScore: Math.max(0, Math.min(100, score)), scoreBreakdown: JSON.stringify(breakdown) };
}

const minAge = Number(cfg.minPostingAgeDays || 28);
const out = [];
for (const job of unique) {
  const age = ageDays(job.postedDate);
  if (age == null || age < minAge) continue;              // staleness floor
  if (cfg.excludeStaffing && isStaffingFirm(job.company)) continue; // skip competitors
  const s = scoreLead(job, age);
  out.push({ json: {
    ...job,
    ...s,
    postingAgeDays: age,
    roleTitle: job.jobTitle || '',
    isHighLead: s.leadScore >= Number(cfg.highLeadThreshold || 50),
    firstSeen: new Date().toISOString(),
    lastSeen: new Date().toISOString(),
    status: 'New',
    _config: carryConfig,
  }});
}

out.sort((a,b) => b.json.leadScore - a.json.leadScore);
return out;

