INSERT INTO seen_leads (lead_id, source, status, first_seen, last_seen, times_seen)
VALUES ($1, $2, 'seen', NOW(), NOW(), 1)
ON CONFLICT (lead_id) DO UPDATE SET last_seen = NOW(), times_seen = seen_leads.times_seen + 1;

parameters.jsCode:
const items = $input.all();

let cfg = items[0]?.json?._config || null;
if (!cfg) { try { cfg = $('Dedup and Score').first()?.json?._config || null; } catch {} }
// Empty webhook URL = Slack disabled; the "Has Notifications?" gate then skips the post.
const slackWebhookUrl = cfg?.slackWebhookUrl || ($env.SLACK_WEBHOOK_URL || '');

let succeeded = 0;
let rateLimited = 0;
let otherFailed = 0;
for (const i of items) {
  const j = i.json || {};
  if (j.lead_id) succeeded += 1;
  else if (Array.isArray(j.errors) && j.errors.some(e => (e.error||'').includes('RATE_LIMIT'))) rateLimited += 1;
  else if (j.errors || j.error) otherFailed += 1;
}
const total = items.length;
// count drives the Slack gate: zero it out when Slack is disabled.
const count = slackWebhookUrl ? succeeded : 0;

let message;
if (total === 0) {
  message = 'No new aging-listing leads added.';
} else if (rateLimited === 0 && otherFailed === 0) {
  message = `${succeeded} new leads added.`;
} else {
  message = `Postgres: ${succeeded} leads added, ${rateLimited} rate-limited, ${otherFailed} other failed (out of ${total}).`;
}

return [{ json: { message, count, succeeded, rateLimited, otherFailed, total, slackWebhookUrl } }];

