// Apify run-sync-get-dataset-items returns an array of dataset items.
// n8n HTTP node delivers it as either {json: <array>} or wraps in {json: {body: <array>}}.
// Explode into one n8n item per dataset record.
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  let arr = null;
  if (Array.isArray(j)) arr = j;
  else if (j && Array.isArray(j.body)) arr = j.body;
  else if (j && Array.isArray(j.data)) arr = j.data;
  else if (j && typeof j === 'object') arr = [j];
  if (!arr) continue;
  for (const r of arr) {
    if (r && typeof r === 'object') out.push({ json: r });
  }
}
return out;

