const NL = String.fromCharCode(10);
const items = $input.all();
const r = (items[0] && items[0].json) || {};
const date = r.date || new Date().toISOString().split('T')[0];
function tryNode(name){ try { const n=$(name).first(); return (n&&n.json&&n.json.slackWebhookUrl)||''; } catch(e){ return ''; } }
let slackWebhookUrl = tryNode('Config');
if (!slackWebhookUrl) slackWebhookUrl = ($env.SLACK_WEBHOOK_URL || '');

// The outreach endpoint response shape may vary; be defensive.
const outreach = r.outreach || r.build || {};
const drafted = Array.isArray(outreach.leads) ? outreach.leads : (Array.isArray(outreach.packages) ? outreach.packages : []);

const lines = [':briefcase: *Recruiter lead run - ' + date + '*'];
if (outreach.error) {
  lines.push('Outreach FAILED: ' + outreach.error);
} else if (drafted.length > 0) {
  lines.push(drafted.length + ' outreach drafts staged (LinkedIn + email):');
  for (const p of drafted.slice(0, 20)) { lines.push('- ' + (p.role_title || p.title || '?') + ' @ ' + (p.company || '?')); }
} else {
  lines.push('Run complete. No outreach drafted this run.');
}
const message = lines.join(NL);
return [{ json: { message, slackWebhookUrl, date, outreach } }];
